{"path": "download_scalp.py", "content": "#!/usr/bin/env python3
"""Download 90d of 5m & 15m klines for liquid altcoins. ~26-90 calls/symbol/interval."""
import urllib.request, json, time, os, datetime

OUT=os.path.join(os.path.dirname(os.path.abspath(__file__)),"pa_scalp")
os.makedirs(OUT,exist_ok=True)
SYMBOLS=["SOLUSDT","DOGEUSDT","AVAXUSDT","LINKUSDT","BNBUSDT","XRPUSDT","NEARUSDT",
         "AAVEUSDT","ETCUSDT","RUNEUSDT","LTCUSDT","TRXUSDT","ADAUSDT","DOTUSDT",
         "MATICUSDT","ATOMUSDT","INJUSDT","SUIUSDT","TIAUSDT","WIFUSDT"]
INTERVALS=["5m","15m"]
END=int(datetime.datetime(2026,7,1,tzinfo=datetime.timezone.utc).timestamp()*1000)
START=END-91*24*3600*1000  # ~90 days

def fetch(sym,interval,start,end):
    url=f"https://api.binance.com/api/v3/klines?symbol={sym}&interval={interval}&startTime={start}&endTime={end}&limit=1000"
    req=urllib.request.Request(url,headers={"User-Agent":"Mozilla/5.0"})
    return json.load(urllib.request.urlopen(req,timeout=30))

def dl(sym,interval):
    rows=[]; start=START; last=0
    while True:
        try: d=fetch(sym,interval,start,END)
        except Exception as e:
            print(f"  [{sym}/{interval}] err {e}, sleep2"); time.sleep(2); continue
        if not d: break
        for c in d: rows.append((c[0],c[1],c[2],c[3],c[4],c[5]))
        last=d[-1][0]
        if len(d)<1000: break
        start=last+1
        if start>=END: break
        time.sleep(0.08)
    seen={r[0]:r for r in rows}; rows=sorted(seen.values(),key=lambda x:x[0])
    p=os.path.join(OUT,f"{sym}_{interval}.csv")
    with open(p,"w") as f:
        f.write("ts,open,high,low,close,volume\n")
        for r in rows: f.write(f"{r[0]},{r[1]},{r[2]},{r[3]},{r[4]},{r[5]}\n")
    print(f"[{sym}/{interval}] {len(rows)} candles -> {p}")

if __name__=="__main__":
    for s in SYMBOLS:
        for iv in INTERVALS:
            dl(s,iv)
    print("ALL DONE")
